module RefModule (
    input clk,
    input reset,
    input [9:0] data,
    output reg parity
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset) begin
            parity <= 1'b0;
        end else begin
            parity <= ^data;
        end
    end

endmodule
